    private boolean checkUpdateStatus(Workflow wf, String apname, String path, String sheet) {
        boolean result =  false;

        try {
            String status = wf.getStatus();


            if (Workflow.PROCESSING.equals(status) || Workflow.REJECTED.equals(status) || Workflow.FINISH.equals(status)) {
                APIQuery aq = new APIQuery(apname, path, sheet);
                aq.setIfEidNaming(true);
                aq.setIfApproval(true);

                APIEntry ae = aq.getAPIEntry(wf.getOriginalNodeId());

                List<String> approvers = wf.getNextUsers();


                List<String> dbStatusList = ae.getFieldValues(DConst.WF_STATUS);
                List<String> dbApprovers = ae.getFieldValues(DConst.WF_NEXT_SIGNER);


                if (dbStatusList.size() == 0 || dbStatusList.size() > 1 || approvers.size() != dbApprovers.size()) {
                    result = true;
                } else if (!status.equals(dbStatusList.get(0)) || !equalsIgnoreOrder(approvers, dbApprovers)) {
                    result = true;
                }
            }
        } catch (NullPointerException ignored) {}
        return result;
    }



    String getDeputy(String apname, String userEmail) {
        String deputy;
        User user = new User();
        user.setUserId(userEmail);
        deputy = user.getDeputyUserId(apname);
        return deputy;
    }

